<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { api, type Plan } from '@/services/api'

const form = ref({ origin_city: '上海', destination_city: '杭州', start_date: '', end_date: '', people_count: '2', budget_total: '4000', interests: '人文街巷、咖啡、自然风光', hotel_level: '舒适型', transport_preference: '高铁优先', pace: '适中', special_requirements: '' })
const loading = ref(false); const historyLoading = ref(true); const error = ref(''); const plan = ref<Plan | null>(null); const histories = ref<Plan[]>([]); const revision = ref(''); const naturalLanguage = ref('')
const today = new Date().toISOString().slice(0, 10)
const planData = computed(() => plan.value?.latest_version?.plan_json || {})
const planDays = computed(() => Array.isArray(planData.value.days) ? planData.value.days as Array<Record<string, unknown>> : [])

async function loadHistory() { historyLoading.value = true; try { histories.value = await api.listPlans() } catch { histories.value = [] } finally { historyLoading.value = false } }
async function generate() { error.value = ''; naturalLanguage.value = ''; if (!form.value.start_date || !form.value.end_date) { error.value = '请先选择出行日期。'; return }; if (form.value.end_date < form.value.start_date) { error.value = '返程日期不能早于出发日期。'; return }; loading.value = true; try { const trip = await api.createTrip({ title: `${form.value.destination_city}旅行`, origin_city: form.value.origin_city, destination_city: form.value.destination_city, start_date: form.value.start_date, end_date: form.value.end_date, timezone: 'Asia/Shanghai', status: 'planned' }); plan.value = await api.generatePlan({ ...form.value, trip_id: trip.id }); await loadHistory() } catch (cause) { error.value = cause instanceof Error ? cause.message : '行程生成失败，请稍后重试。' } finally { loading.value = false } }
async function revise() { if (!plan.value || !revision.value.trim()) return; loading.value = true; try { plan.value = await api.revisePlan(plan.value.id, revision.value); revision.value = '' } catch (cause) { error.value = cause instanceof Error ? cause.message : '调整失败。' } finally { loading.value = false } }
async function humanize() { if (!plan.value) return; loading.value = true; try { naturalLanguage.value = (await api.humanizePlan(plan.value.id)).natural_language } catch (cause) { error.value = cause instanceof Error ? cause.message : '暂时无法生成讲解。' } finally { loading.value = false } }
function printPlan() { globalThis.print() }
async function openHistory(item: Plan) { loading.value = true; error.value = ''; try { plan.value = await api.getPlan(item.id) } catch (cause) { error.value = cause instanceof Error ? cause.message : '读取失败。' } finally { loading.value = false } }
onMounted(loadHistory)
</script>

<template>
  <div class="page planner-page">
    <section class="hero"><div><p class="eyebrow">PLAN WITH CONFIDENCE</p><h1>把旅行的期待，<br>变成可执行的路线。</h1><p>填写真实的行程偏好，系统会先创建行程，再调用规划接口生成可调整的方案。</p></div><div class="hero-mark">✦</div></section>
    <div class="planner-grid">
      <section class="card form-card"><div class="heading"><span>01</span><div><h2>行程信息</h2><p>越具体，建议越贴合。</p></div></div><div class="field-grid"><label>出发城市<input v-model="form.origin_city"></label><label>目的地<input v-model="form.destination_city"></label><label>出发日期<input v-model="form.start_date" :min="today" type="date"></label><label>返程日期<input v-model="form.end_date" :min="form.start_date || today" type="date"></label><label>同行人数<select v-model="form.people_count"><option value="1">1 人</option><option value="2">2 人</option><option value="3">3—4 人</option><option value="5">5 人以上</option></select></label><label>总预算（元）<input v-model="form.budget_total" inputmode="numeric"></label></div><div class="heading compact"><span>02</span><h2>旅行偏好</h2></div><label class="wide">想体验什么？<textarea v-model="form.interests" rows="2" placeholder="如：历史人文、亲子、摄影、美食"></textarea></label><div class="field-grid"><label>住宿标准<select v-model="form.hotel_level"><option>经济实惠</option><option>舒适型</option><option>高品质</option></select></label><label>交通偏好<select v-model="form.transport_preference"><option>高铁优先</option><option>自驾优先</option><option>公共交通</option></select></label><label>旅行节奏<select v-model="form.pace"><option>轻松</option><option>适中</option><option>充实</option></select></label></div><label class="wide">特别需求（可选）<textarea v-model="form.special_requirements" rows="2" placeholder="如：老人同行、避开排队、必须去的景点"></textarea></label><button class="primary" :disabled="loading" @click="generate">{{ loading ? '正在生成行程…' : '生成我的旅行计划 →' }}</button><p v-if="error" class="error">{{ error }}</p></section>
      <aside class="side"><section class="card"><p class="eyebrow">SAVED PLANS</p><h2>最近行程</h2><p v-if="historyLoading" class="muted">正在读取…</p><button v-for="item in histories.slice(0, 4)" :key="item.id" class="history" @click="openHistory(item)"><b>{{ item.destination_city }} · {{ item.title }}</b><small>{{ item.start_date }} 至 {{ item.end_date }}</small></button><p v-if="!historyLoading && !histories.length" class="muted">还没有已保存的行程。</p></section><section class="card note"><b>生成流程</b><p>行程创建成功后，规划请求会携带真实的 <code>trip_id</code>，保证后续陪伴和创作可以关联同一趟旅行。</p></section></aside>
    </div>
    <section v-if="plan" class="result"><div class="result-head"><div><p class="eyebrow">YOUR ITINERARY · V{{ plan.latest_version?.version_no || 1 }}</p><h2>{{ String(planData.title || `${plan.destination_city}旅行计划`) }}</h2><p>{{ String(planData.summary || '已生成一份可继续调整的旅行建议。') }}</p></div><div><button class="secondary" :disabled="loading" @click="humanize">自然讲解</button><button class="secondary" :disabled="loading" @click="printPlan">打印</button></div></div><p v-if="naturalLanguage" class="narrative">{{ naturalLanguage }}</p><div v-if="planDays.length" class="days"><article v-for="(day, index) in planDays" :key="index" class="card day"><span>DAY {{ index + 1 }}</span><h3>{{ String(day.title || day.date || `第 ${index + 1} 天`) }}</h3><p>{{ String(day.summary || day.description || '') }}</p><div v-if="Array.isArray(day.activities)" class="activities"><i v-for="(activity, key) in day.activities" :key="key">{{ typeof activity === 'string' ? activity : JSON.stringify(activity) }}</i></div></article></div><pre v-else class="card raw">{{ JSON.stringify(planData, null, 2) }}</pre><div class="revision"><input v-model="revision" placeholder="例如：把第二天安排得轻松一些"><button class="primary" :disabled="loading || !revision.trim()" @click="revise">提交调整</button></div></section>
  </div>
</template>

<style scoped>
.planner-page{max-width:1180px;margin:auto;padding:42px 26px 70px}.hero{display:flex;justify-content:space-between;align-items:center;min-height:200px;margin-bottom:28px;padding:30px 38px;border:1px solid #dcebdd;border-radius:26px;background:radial-gradient(circle at 88% 35%,#d5f0df 0,transparent 23%),linear-gradient(115deg,#fff,#eef8f0)}.eyebrow{margin:0 0 9px;color:#539177;letter-spacing:.13em;font-size:11px;font-weight:700}.hero h1,.result h2{margin:0;color:#234837;font:700 clamp(29px,4vw,46px)/1.28 'Noto Serif SC','Microsoft YaHei',serif}.hero p:last-child{max-width:550px;color:#718178;line-height:1.8}.hero-mark{display:grid;place-items:center;width:85px;height:85px;border-radius:28px;background:#2d785d;color:white;font-size:38px;box-shadow:0 14px 28px #bdddc7}.planner-grid{display:grid;grid-template-columns:minmax(0,1fr) 290px;gap:22px}.card{border:1px solid #e2ebe3;border-radius:18px;background:#fff;box-shadow:0 10px 28px rgba(39,91,66,.06)}.form-card{padding:30px}.heading{display:flex;align-items:center;gap:12px;margin-bottom:18px}.heading span{display:grid;place-items:center;width:29px;height:29px;border-radius:9px;background:#e1f3e7;color:#297755;font-size:12px;font-weight:800}.heading h2,.side h2{margin:0;color:#294a3b;font-size:19px}.heading p{margin:4px 0 0;color:#85928a;font-size:12px}.compact{margin-top:26px}.field-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:13px}.form-card label{display:grid;gap:7px;color:#65776d;font-size:12px;font-weight:700}.form-card input,.form-card select,.form-card textarea,.revision input{box-sizing:border-box;width:100%;border:1px solid #dfe8e1;border-radius:10px;padding:10px 11px;background:#fbfdfb;color:#283e34;outline:0}.form-card textarea{resize:vertical}.form-card input:focus,.form-card select:focus,.form-card textarea:focus,.revision input:focus{border-color:#69b390;box-shadow:0 0 0 3px #e6f4ea}.wide{margin:15px 0}.primary,.secondary{border:0;border-radius:10px;padding:11px 16px;font-weight:700;cursor:pointer}.primary{margin-top:20px;background:#2c775b;color:#fff}.primary:disabled{opacity:.6;cursor:wait}.error{margin:13px 0 0;color:#b74c4c;font-size:13px}.side{display:grid;gap:18px;align-content:start}.side .card{padding:22px}.history{display:grid;width:100%;gap:4px;padding:12px 0;border:0;border-bottom:1px solid #edf2ee;background:transparent;text-align:left;cursor:pointer}.history b{color:#40584d;font-size:13px}.history small,.muted,.note p{color:#829088;font-size:12px;line-height:1.65}.note{background:#f4faf5}.note code{color:#2c7c5e}.result{margin-top:29px}.result-head{display:flex;justify-content:space-between;gap:20px;align-items:start;margin-bottom:18px}.result h2{font-size:28px}.result-head p:last-child{color:#738278}.secondary{margin-left:8px;border:1px solid #d8e6dc;background:#fff;color:#39725b}.narrative,.raw{padding:20px;line-height:1.8;color:#436053}.days{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:15px}.day{padding:21px}.day span{color:#5d9a7f;font-size:11px;font-weight:800}.day h3{margin:9px 0;color:#315044}.day p{color:#738177;font-size:13px;line-height:1.7}.activities{display:grid;gap:7px}.activities i{border-radius:8px;padding:7px;background:#f3f8f4;color:#4e675b;font-size:12px;font-style:normal}.raw{overflow:auto}.revision{display:flex;gap:10px;margin-top:17px}.revision .primary{margin:0;white-space:nowrap}@media(max-width:760px){.planner-page{padding:26px 16px}.hero{padding:27px 22px}.hero-mark{display:none}.planner-grid{grid-template-columns:1fr}.field-grid{grid-template-columns:1fr}.result-head{display:block}.result-head>div:last-child{margin-top:14px}.revision{flex-direction:column}.revision .primary{width:100%}}
</style>
